import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public void displayUserInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        String safeUserInput = Encode.forHtml(userInput);

        String htmlResponse = "<html><body>";
        htmlResponse += "<h1>User Input: " + safeUserInput + "</h1>";
        htmlResponse += "</body></html>";

        response.setContentType("text/html");
        response.getWriter().write(htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
